import React from "react";
import {
  BrowserRouter as Router,
  Routes,
  Route,
  Navigate,
} from "react-router-dom";

import Login from "./pages/Login";
import Dashboard from "./pages/Dashboard";

// Inline placeholder so routing works even if you haven't created a SignUp file yet.
function SignUpPlaceholder() {
  return (
    <div className="g-auth-bg">
      <div className="g-auth-card">
        <h1 className="g-title">Sign up</h1>
        <p className="g-subtitle">Create an account</p>
        <p style={{ color: "#5f6368" }}>
          Create src/pages/SignUp.js and route will display your form here.
        </p>
      </div>
    </div>
  );
}

export default function App() {
  return (
    <Router>
      <Routes>
        <Route path="/" element={<Login />} />
        <Route path="/signup" element={<SignUpPlaceholder />} />
        <Route path="/dashboard" element={<Dashboard />} />
        <Route path="*" element={<Navigate to="/" replace />} />
      </Routes>
    </Router>
  );
}
